// Churn-Score-Berechnung pro Kunde (0-100, höher = mehr Churn-Risiko).
// Heuristik-Modell — anpassbar an dein Geschäftsmodell.
const cfg = $('Set: Churn-Konfiguration').first().json;
const now = Date.now();
const out = [];

for (const item of $input.all()) {
  const r = item.json;
  let score = 0;
  const reasons = [];

  // 1) Inaktivität (Login)
  const lastLogin = r.last_login_at ? new Date(r.last_login_at).getTime() : null;
  const daysInactive = lastLogin ? Math.floor((now - lastLogin) / 86400000) : 999;
  if (daysInactive >= cfg.inactiveDaysCritical) { score += 40; reasons.push(`${daysInactive} Tage kein Login`); }
  else if (daysInactive >= cfg.inactiveDaysWarn) { score += 20; reasons.push(`${daysInactive} Tage kein Login`); }

  // 2) Sinkende Nutzung (Sessions 30d vs. vorherige 30d)
  const cur = Number(r.sessions_30d) || 0;
  const prev = Number(r.sessions_prev_30d) || 0;
  if (prev > 0) {
    const drop = (prev - cur) / prev;
    if (drop >= 0.7) { score += 25; reasons.push(`Nutzung -${Math.round(drop*100)}%`); }
    else if (drop >= 0.4) { score += 15; reasons.push(`Nutzung -${Math.round(drop*100)}%`); }
  } else if (cur === 0) { score += 15; reasons.push('Keine Sessions im 30d-Fenster'); }

  // 3) Zahlungsausfälle
  const failed = Number(r.failed_payments) || 0;
  if (failed >= 2) { score += 20; reasons.push(`${failed} fehlgeschlagene Zahlungen`); }
  else if (failed === 1) { score += 10; reasons.push('1 fehlgeschlagene Zahlung'); }

  // 4) Offene Support-Tickets (Frust-Signal)
  const tickets = Number(r.open_tickets) || 0;
  if (tickets >= 3) { score += 10; reasons.push(`${tickets} offene Tickets`); }

  // 5) Niedrige Feature-Adoption
  const adoption = Number(r.feature_adoption_pct) || 0;
  if (adoption < 20) { score += 10; reasons.push(`Feature-Adoption ${adoption}%`); }

  score = Math.min(100, score);
  let band = 'OK';
  if (score >= 80) band = 'CRITICAL';
  else if (score >= cfg.riskThreshold) band = 'AT_RISK';
  else if (score >= 30) band = 'WATCH';

  out.push({ json: {
    customer_id: r.customer_id,
    customer_name: r.customer_name,
    customer_email: r.customer_email,
    plan: r.plan,
    mrr: Number(r.mrr) || 0,
    days_inactive: daysInactive,
    sessions_30d: cur,
    sessions_prev_30d: prev,
    failed_payments: failed,
    open_tickets: tickets,
    feature_adoption_pct: adoption,
    churn_score: score,
    risk_band: band,
    risk_reasons: reasons,
    risk_reasons_text: reasons.join('; ') || 'keine'
  }});
}

return out;

