// KI-Antwort robust parsen. Fallback wenn KI-JSON kaputt. Reihenfolge bleibt erhalten
// und wird im Merge (combineByPosition) wieder mit dem passenden Kunden gepaart.
const out = [];
for (const item of $input.all()) {
  const base = item.json;
  let ai = { assessment: '', email_subject: '', email_body: '' };
  try {
    const raw = base.choices?.[0]?.message?.content ?? '{}';
    ai = typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch (e) {
    ai = {
      assessment: 'KI-Analyse nicht verfügbar — manueller Review nötig.',
      email_subject: 'Wir vermissen dich',
      email_body: 'Hallo, wir haben gesehen, dass du eine Weile nicht aktiv warst. Können wir dir bei etwas helfen? Antworte einfach auf diese Mail.'
    };
  }
  out.push({ json: { ai_assessment: ai.assessment || '', ai_email_subject: ai.email_subject || 'Können wir helfen?', ai_email_body: ai.email_body || '' } });
}
return out;

